    "id": "remote-bind-exposes-agent-clis",
    "severity": "HIGH",
    "category": "security",
    "location": "scripts/ai_agent_bridge/_cli.py:681",
    "description": "The new `--host` option accepts arbitrary bind addresses and `uvicorn.run` uses it directly, so `ab serve --openai --host 0.0.0.0` exposes an unauthenticated endpoint that can execute local Codex/Gemini/Claude/Hermes CLIs with the user's credentials and environment. The docs describe this as localhost-only tooling, but the code has no explicit opt-in guard such as `--allow-remote` or host validation."
  },
  {
    "id": "unbounded-request-spawns-subprocess",
    "severity": "MEDIUM",
    "category": "dos-surface",
    "location": "scripts/ai_agent_bridge/openai_proxy.py:326",
    "description": "The chat completions endpoint accepts unbounded `messages` content and synchronously starts a backend subprocess per request, with each process allowed to run for up to 120 seconds. A local or accidentally exposed client can submit very large prompts or many concurrent requests and consume memory, CPU, process slots, and paid/model CLI quota; there is no request body limit, prompt length cap, or concurrency gate at the proxy boundary."
  },
  {
    "id": "stream-parameter-ignored",
    "severity": "MEDIUM",
    "category": "spec-compliance",
    "location": "scripts/ai_agent_bridge/openai_proxy.py:326",
    "description": "Because the request model allows extra OpenAI fields but the endpoint ignores them, a client sending `stream: true` receives a normal JSON completion instead of an event-stream response or a clear unsupported-parameter error. Many OpenAI-compatible clients switch parsing behavior based on `stream`, so this will fail at runtime in a way that looks like a protocol bug rather than an intentional Phase 1 limitation."
  }
]
